// Data + pure helpers for the About page (Overview / Acknowledgements /
// Licenses tabs). The license inventory is a build-time artifact
// (`public/licenses.json`, generated by scripts/gen-licenses.mjs) fetched
// lazily only when the Licenses tab is opened — it is never part of the app's
// initial payload.

/** A single dependency and its license. Mirrors the generator's JSON shape. */
export interface LicensePackage {
  ecosystem: "rust" | "npm";
  name: string;
  version: string;
  /** SPDX expression (e.g. "MIT OR Apache-2.0") or "UNKNOWN". */
  license: string;
  repository: string;
  /** Full license text; "" when unavailable (degraded build). */
  licenseText: string;
}

/** The full license-inventory document. */
export interface LicensesData {
  /** Always null today (the generator keeps the artifact deterministic). */
  generatedAt: string | null;
  /** False when any source was skipped/degraded (e.g. cargo missing). */
  complete: boolean;
  /** Human-readable caveat; "" when fully complete. */
  note: string;
  /** Per-ecosystem package counts. */
  ecosystems: Record<string, number>;
  packages: LicensePackage[];
}

/**
 * A hand-curated entry for the Acknowledgements tab — the projects gpm leans
 * on most. `descKey` resolves through the `about` i18n bundle so each is
 * translated for the active locale.
 */
export interface Acknowledgement {
  id: string;
  name: string;
  url: string;
  license: string;
  /** i18n key suffix under `about.ack.<id>`. */
  descKey: string;
}

