// ── License-inventory fetch (lazy, cached, failure-tolerant) ────────────────

let cache: Promise<LicensesData> | null = null;

/**
 * Test-only seam to drop the session cache between tests. Production code never
 * resets — the inventory is fetched once per session.
 * @internal
 */
export function __resetLicensesCacheForTests(): void {
  cache = null;
}

/**
 * Fetch the license inventory once per session. Resolves to a degraded
 * (empty-packages) document on any failure so the UI always has a typed shape
 * to render — the Licenses tab shows its "unavailable" state from
 * `data.complete` / `data.packages.length`, never a thrown exception.
 */
export function fetchLicenses(): Promise<LicensesData> {
  if (!cache) {
    const url = `${import.meta.env.BASE_URL}licenses.json`;
    cache = fetch(url)
      .then((r) => {
        if (!r.ok) throw new Error(`licenses.json HTTP ${r.status}`);
        return r.json() as Promise<LicensesData>;
      })
      .catch((e): LicensesData => {
        // Don't cache the failure forever — a retry (page re-mount) should try
        // again, since the vite plugin may have just written the file.
        cache = null;
        return {
          generatedAt: null,
          complete: false,
          note: String(e?.message ?? e),
          ecosystems: {},
          packages: [],
        };
      });
  }
  return cache;
}

// ── Pure grouping + filtering helpers (unit-tested) ─────────────────────────

/** A license group: all packages sharing one SPDX expression. */
export interface LicenseGroup {
  license: string;
  count: number;
  packages: LicensePackage[];
}

/**
 * Group packages by SPDX expression, most-populous first (then alphabetically).
 * The vast majority of deps share a handful of expressions (mostly
 * "MIT OR Apache-2.0"), so this collapses hundreds of packages into ~8-15
 * collapsible rows — the UI's primary scale-control.
 */
export function groupLicenses(
  packages: readonly LicensePackage[],
): LicenseGroup[] {
  const map = new Map<string, LicensePackage[]>();
  for (const p of packages) {
    const key = p.license || "UNKNOWN";
    let arr = map.get(key);
    if (!arr) {
      arr = [];
      map.set(key, arr);
    }
    arr.push(p);
  }
  return [...map.entries()]
    .map(([license, pkgs]) => ({
      license,
      count: pkgs.length,
      // Stable sub-ordering: ecosystem, then name, then version.
      packages: pkgs
        .slice()
        .sort((a, b) =>
          a.ecosystem !== b.ecosystem
            ? a.ecosystem < b.ecosystem
              ? -1
              : 1
            : a.name !== b.name
              ? a.name < b.name
                ? -1
                : 1
              : a.version < b.version
                ? -1
                : a.version > b.version
                  ? 1
                  : 0,
        ),
    }))
    .sort((a, b) =>
      b.count !== a.count ? b.count - a.count : a.license < b.license ? -1 : 1,
    );
}

/**
 * Case-insensitive substring match across name (and license, so a search for
 * "apache" finds every Apache-licensed dep). Used for the Licenses-tab search
 * box; returns packages in display order.
 */
export function filterPackages(
  packages: readonly LicensePackage[],
  query: string,
): LicensePackage[] {
  const q = query.trim().toLowerCase();
  if (!q) return packages.slice();
  return packages.filter(
    (p) =>
      p.name.toLowerCase().includes(q) ||
      p.license.toLowerCase().includes(q) ||
      p.version.toLowerCase().includes(q),
  );
}
